final:
module top_module(
	input [7:0] x,
	input [7:0] y,
	output out
);wire [9:0] or_results;
wire [4:0] or_outputs;

genvar i;

generate
	// Create 8 AND gates
	for(i = 0; i < 8; i = i + 1)
	begin: and_1st_row
		assign or_results[i] = x[i] & y[i];
	end

	// Create 4 OR gates
	for(i = 0; i < 4; i = i + 1)
	begin: or_2nd_row
		assign or_outputs[i] = or_results[2 * i] | or_results[2 * i + 1];
	end

	// Create 2 AND gates
	assign or_results[8] = or_outputs[0] & or_outputs[1];
	assign or_results[9] = or_outputs[2] & or_outputs[3];

	// Create 1 OR gate
	assign out = or_results[8] | or_results[9];

endgenerate

endmodule
